 export function releasePathChunkLanes(chunk, options = {}) {
   const base = releasePathChunks[chunk];
   if (!base) {
     throw new Error(
       `OPENCLAW_DOCKER_ALL_CHUNK must be one of: ${Object.keys(releasePathChunks).join(", ")}. Got: ${JSON.stringify(chunk)}`,
     );
   }
